// // This module implements a 2-bit down counter that counts from 3 to 0.
module counter_2bit (
    input wire clk,
    input wire rst,
    output reg [1:0] count
);

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            count <= 2'b00;
        end else begin
            count <= count + 1;
        end
    end
endmodule
